512	    async fn scroll(
513	        &self,
514	        pixels: Option<i32>,
515	        selector: Option<&str>,
516	    ) -> Result<ActionOutcome, BrowserError> {
517	        let start = std::time::Instant::now();
518	
519	        let script = if let Some(sel) = selector {
520	            format!(
521	                "document.querySelector('{}')?.scrollIntoView({{ behavior: 'instant', block: 'center' }});",
522	                escape_js_string(sel)
523	            )
524	        } else if let Some(px) = pixels {
525	            format!("window.scrollBy(0, {px});")
526	        } else {
527	            "window.scrollBy(0, 300);".to_string()
528	        };
529	
530	        let cmd = command::runtime_evaluate(&script);
531	        let _ = self
532	            .connection
533	            .send_command(cmd, Duration::from_secs(5))
534	            .await;
535	
536	        let elapsed = start.elapsed();
537	
538	        Ok(ActionOutcome {
539	            success: true,
540	            error_message: None,
541	            execution_time_ms: elapsed.as_millis() as u64,
542	            page_url_after: Some(self.current_url.lock().await.clone()),
543	            dom_changed: false,
544	        })
545	    }
