52	    /// Create a new session by launching a Chromium instance.
53	    /// If `start_url` is provided, navigate to it immediately.
54	    pub async fn create(
55	        &self,
56	        goal_id: Uuid,
57	        start_url: Option<String>,
58	    ) -> Result<Uuid, BrowserError> {
59	        let session_id = Uuid::new_v4();
60	        tracing::info!(%session_id, %goal_id, "Creating session");
61	
62	        let backend = CdpBackend::launch(Some(StealthConfig::standard())).await?;
63	
64	        if let Some(url) = &start_url {
65	            let _ = backend
66	                .navigate(url, Duration::from_secs(10))
67	                .await
68	                .map(|state| {
69	                    tracing::info!(url = %state.url, "Session started at URL");
70	                });
71	        }
72	
73	        let handle = SessionHandle {
74	            session_id,
75	            goal_id,
76	            backend,
77	            current_url: start_url.unwrap_or_else(|| "about:blank".into()),
78	            status: SessionStatus::Idle,
79	        };
80	
81	        self.sessions.write().await.insert(session_id, handle);
82	
83	        Ok(session_id)
84	    }
